ambiguous_dsl.choice_dsl:
PREFIX : <http://ambrosia.example.org/jobpostings#>
PREFIX p: <http://ambrosia.example.org/jobpostings/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
CHOICE attachment {
  high: { SELECT DISTINCT ?o0 WHERE {
  {
    ?university a :University .
    ?chemist a :Chemist .
    ?chemist p:hasUniversity ?university .
    ?chemist p:name ?fullname .
    ?university p:name ?name_f .
    FILTER(STR(?name_f) = "MIT")
    BIND(?fullname AS ?o0)
  }
  UNION
  {
    ?university a :University .
    ?geoscientist a :Geoscientist .
    ?geoscientist p:hasUniversity ?university .
    ?geoscientist p:name ?fullname .
    ?university p:name ?name_f .
    FILTER(STR(?name_f) = "MIT")
    BIND(?fullname AS ?o0)
  }
} }
  low: { SELECT DISTINCT ?o0 WHERE {
  {
    ?university a :University .
    ?chemist a :Chemist .
    ?chemist p:hasUniversity ?university .
    ?chemist p:name ?fullname .
    BIND(?fullname AS ?o0)
  }
  UNION
  {
    ?university a :University .
    ?geoscientist a :Geoscientist .
    ?geoscientist p:hasUniversity ?university .
    ?geoscientist p:name ?fullname .
    ?university p:name ?name_f .
    FILTER(STR(?name_f) = "MIT")
    BIND(?fullname AS ?o0)
  }
} }
}
